class Solution:
    def stableMountains(self, height, threshold):
        n = len(height)
        result = []
        for i in range(n):
            if i == 0:
                continue
            predecessor_height = height[i - 1]
            is_stable = predecessor_height > threshold
            if is_stable:
                result.append(i)
        return result

